# Math utilities module providing calculation helpers

def square(x: int) -> int:
    return x * x

def cube(x: int) -> int:
    return x * x * x

def average(values: list[int]) -> float:
    if len(values) == 0:
        return 0.0
    total: int = sum(values)
    return total / len(values)

def clamp(value: int, min_val: int, max_val: int) -> int:
    if value < min_val:
        return min_val
    if value > max_val:
        return max_val
    return value

class Calculator:
    result: float

    def __init__(self):
        self.result = 0.0

    def add(self, x: float) -> float:
        self.result += x
        return self.result

    def multiply(self, x: float) -> float:
        self.result *= x
        return self.result

    def clear(self) -> None:
        self.result = 0.0

