# Text utilities module for string formatting and manipulation

def repeat(text: str, count: int) -> str:
    result: str = ""
    for i in range(count):
        result += text
    return result

def pad_left(text: str, width: int, char: str = " ") -> str:
    if len(text) >= width:
        return text
    padding: int = width - len(text)
    pad_str: str = repeat(char, padding)
    return pad_str + text

def truncate(text: str, max_len: int) -> str:
    if len(text) <= max_len:
        return text
    return text[:max_len - 3] + "..."

def is_palindrome(text: str) -> bool:
    normalized: str = text.lower()
    left: int = 0
    right: int = len(text) - 1
    while left < right:
        if str(normalized[left]) != str(normalized[right]):
            return False
        left += 1
        right -= 1
    return True

class TextFormatter:
    prefix: str
    suffix: str

    def __init__(self, prefix: str = "", suffix: str = ""):
        self.prefix = prefix
        self.suffix = suffix

    def format(self, text: str) -> str:
        return self.prefix + text + self.suffix

    @staticmethod
    def with_brackets() -> TextFormatter:
        return TextFormatter("[", "]")

    def set_delimiters(self, open_delim: str, close_delim: str) -> None:
        self.prefix = open_delim
        self.suffix = close_delim
